  <script>
  var animatedElements = document.querySelectorAll(\'.animate-scroll\');

  var observer = new IntersectionObserver(function(entries) {
    entries.forEach(function(entry) {
      if (entry.isIntersecting) {
        entry.target.classList.add(\'animate\');
        observer.unobserve(entry.target);
      }
    });
  }, { threshold: 0.1 });

  animatedElements.forEach(function(el) {
    observer.observe(el);
  });
</script>

<script>
(function(){
  //Compteur 31 Janvier 2026 à 00:00:00 (heure locale)
  var target = new Date(2026, 0, 31, 0, 0, 0);

  var d = document.getElementById(\'j243Days\');
  var h = document.getElementById(\'j243Hours\');
  var m = document.getElementById(\'j243Mins\');
  var s = document.getElementById(\'j243Secs\');

  if(!d || !h || !m || !s) return;

  function pad(n){
    n = String(n);
    while(n.length < 2) n = \'0\' + n;
    return n;
  }

  function tick(){
    var now = new Date();
    var diff = target.getTime() - now.getTime();

    if(diff <= 0){
      d.textContent = \'00\';
      h.textContent = \'00\';
      m.textContent = \'00\';
      s.textContent = \'00\';
      return;
    }

    var totalSeconds = Math.floor(diff / 1000);
    var days  = Math.floor(totalSeconds / (3600 * 24));
    var hours = Math.floor((totalSeconds % (3600 * 24)) / 3600);
    var mins  = Math.floor((totalSeconds % 3600) / 60);
    var secs  = totalSeconds % 60;

    d.textContent = pad(days);
    h.textContent = pad(hours);
    m.textContent = pad(mins);
    s.textContent = pad(secs);
  }

  tick();
  setInterval(tick, 1000);
})();
</script>

   
 
 
 <script>
/*
⚠️ NOTE IMPORTANT
Ce script utilise du JavaScript moderne (ES6).
Les anciennes versions de Dreamweaver peuvent afficher
une "erreur de syntaxe" qui est un faux positif.

➡ Le script fonctionne correctement dans tous les navigateurs modernes
(Chrome, Firefox, Edge, Safari, mobile).

Merci de NE PAS modifier ce code pour satisfaire Dreamweaver.
*/

  (function(){
    const root = document.getElementById(\'fonctionnement\');
    if(!root) return;

    const steps = Array.from(root.querySelectorAll(\'.j243-step\'));
    const items = Array.from(root.querySelectorAll(\'.j243-acc-item\'));

    function setActiveStep(n){
      steps.forEach(b=>{
        const isActive = b.getAttribute(\'data-step\') === String(n);
        b.classList.toggle(\'is-active\', isActive);
        if(isActive){
          b.setAttribute(\'aria-current\',\'step\');
        }else{
          b.removeAttribute(\'aria-current\');
        }
      });
    }

    function closeAll(){
      items.forEach(it=>{
        const btn = it.querySelector(\'.j243-acc-btn\');
        const panel = it.querySelector(\'.j243-acc-panel\');
        const icon = it.querySelector(\'.j243-acc-icon\');
        it.classList.remove(\'is-open\');
        btn.setAttribute(\'aria-expanded\',\'false\');
        panel.style.maxHeight = \'0px\';
        icon.textContent = \'+\';
      });
    }

    function openItem(step){
      const it = items.find(x => x.getAttribute(\'data-step\') === String(step));
      if(!it) return;
      const btn = it.querySelector(\'.j243-acc-btn\');
      const panel = it.querySelector(\'.j243-acc-panel\');
      const icon = it.querySelector(\'.j243-acc-icon\');

      closeAll();
      it.classList.add(\'is-open\');
      btn.setAttribute(\'aria-expanded\',\'true\');
      panel.style.maxHeight = panel.scrollHeight + \'px\';
      icon.textContent = \'−\';
      setActiveStep(step);
    }

    // Accordion click
    items.forEach(it=>{
      const btn = it.querySelector(\'.j243-acc-btn\');
      btn.addEventListener(\'click\', ()=>{
        const step = it.getAttribute(\'data-step\');
        const expanded = btn.getAttribute(\'aria-expanded\') === \'true\';
        if(expanded){
          closeAll();
          setActiveStep(step); // garde visuellement
        }else{
          openItem(step);
        }
      });
    });

    // Step click -> open corresponding accordion item
    steps.forEach(b=>{
      b.addEventListener(\'click\', ()=>{
        openItem(b.getAttribute(\'data-step\'));
        // option: scroll doux vers l\'accordéon
        const top = root.querySelector(\'.j243-accordion\');
        if(top){
          top.scrollIntoView({behavior:\'smooth\', block:\'start\'});
        }
      });
    });

    // Init: open step 1 if not already
    openItem(1);

    // Recalculate open panel height on resize (important for mobile)
    window.addEventListener(\'resize\', ()=>{
      const opened = root.querySelector(\'.j243-acc-item.is-open .j243-acc-panel\');
      if(opened) opened.style.maxHeight = opened.scrollHeight + \'px\';
    });
  })();
</script>




<script>
document.addEventListener("DOMContentLoaded", function () {
  var questions = document.querySelectorAll(".j243-faq-question");

  for (var i = 0; i < questions.length; i++) {
    questions[i].addEventListener("click", function () {
      this.parentNode.classList.toggle("open");
    });
  }
});
</script>



<script>
(function(){
  function initServicewAccordion(){
    var root = document.querySelector(\'#NosServices .servicew-acc\');
    if(!root) return;

    var items = Array.from(root.querySelectorAll(\'.servicew-item\'));

    // Inject +/− + badge
    items.forEach(function(item){
      var head = item.querySelector(\'.servicew-head\');
      var body = item.querySelector(\'.servicew-body\');
      if(!head || !body) return;

      // Sign
      if(!head.querySelector(\'.servicew-sign\')){
        var sign = document.createElement(\'span\');
        sign.className = \'servicew-sign\';
        head.appendChild(sign);
      }

      // Badge
      var badgeText = head.getAttribute(\'data-servicew-badge\');
      if(badgeText && !head.querySelector(\'.servicew-badge\')){
        var badge = document.createElement(\'span\');
        badge.className = \'servicew-badge\';
        var low = badgeText.toLowerCase();
        if(low.indexOf(\'clé\') !== -1) badge.classList.add(\'key\');
        if(low.indexOf(\'lancement\') !== -1) badge.classList.add(\'launch\');
        badge.textContent = badgeText;
        head.appendChild(badge);
      }

      // Accessibility
      head.setAttribute(\'role\',\'button\');
      head.setAttribute(\'tabindex\',\'0\');
      head.setAttribute(\'aria-expanded\',\'false\');
      body.setAttribute(\'aria-hidden\',\'true\');

      function toggle(open){
        var isOpen = item.classList.contains(\'is-open\');
        var wantOpen = (open === undefined) ? !isOpen : open;

        if(wantOpen){
          item.classList.add(\'is-open\');
          head.setAttribute(\'aria-expanded\',\'true\');
          body.setAttribute(\'aria-hidden\',\'false\');
          // set max-height to content
          body.style.maxHeight = body.scrollHeight + \'px\';
        }else{
          item.classList.remove(\'is-open\');
          head.setAttribute(\'aria-expanded\',\'false\');
          body.setAttribute(\'aria-hidden\',\'true\');
          body.style.maxHeight = \'0px\';
        }
      }

      head.addEventListener(\'click\', function(){ toggle(); });
      head.addEventListener(\'keydown\', function(e){
        if(e.key === \'Enter\' || e.key === \' \'){
          e.preventDefault();
          toggle();
        }
      });

      // Recalc on resize for open items
      window.addEventListener(\'resize\', function(){
        if(item.classList.contains(\'is-open\')){
          body.style.maxHeight = body.scrollHeight + \'px\';
        }
      });
    });

    // 1er ouvert par défaut
    var openFirst = root.getAttribute(\'data-servicew-open-first\') === \'true\';
    if(openFirst && items.length){
      var first = items[0];
      if(first){
        var body = first.querySelector(\'.servicew-body\');
        var head = first.querySelector(\'.servicew-head\');
        first.classList.add(\'is-open\');
        if(head){ head.setAttribute(\'aria-expanded\',\'true\'); }
        if(body){
          body.setAttribute(\'aria-hidden\',\'false\');
          body.style.maxHeight = body.scrollHeight + \'px\';
        }
      }
    }
  }

  if(document.readyState === \'loading\'){
    document.addEventListener(\'DOMContentLoaded\', initServicewAccordion);
  }else{
    initServicewAccordion();
  }
})();
</script>



</body>
</html>
