<style>
.mail-confirm-wrapper{
  max-width:720px;
  margin:1px auto;
  padding:0 2px;
}

.mail-confirm-box{
  background:#ffffff;
  border:1px solid #e5e7eb;
  border-radius:18px;
  padding:18px;
  box-shadow:0 18px 45px rgba(0,0,0,.12);
  text-align:center;
}

/* Logo */
.mail-confirm-logo{
  display:flex;
  justify-content:center;
  margin-bottom:10px;
}

.mail-confirm-logo img{
  max-width:92px;
  height:auto;
  border-radius:14px;
 /* box-shadow:0 10px 24px rgba(0,0,0,.12);*/
}

/* Titre */
.mail-confirm-title{
  display:flex;
  align-items:center;
  justify-content:center;
  gap:10px;
  font-size:22px;
  font-weight:900;
  color:#111827;
  margin-bottom:10px;
}

.mail-confirm-title i{
  color:#666;
  font-size:22px;
}

.mail-confirm-text{
  font-size:14.5px;
  color:#374151;
  margin-bottom:16px;
  line-height:1.5;
}

/* Bloc interne */
.mail-access-box{
  background:#f9fafb;
  border-radius:14px;
  padding:16px;
  box-shadow:0 10px 26px rgba(0,0,0,.08);
}

.mail-access-text{
  font-size:14px;
  font-weight:700;
  margin-bottom:12px;
  color:#111827;
}

/* Boutons */
.mail-btn{
  display:inline-flex;
  align-items:center;
  justify-content:center;
  gap:8px;
  padding:12px 14px;
  border-radius:10px;
  font-weight:900;
  font-size:13.5px;
  text-decoration:none;

  /* ✅ Texte en blanc pour le contraste */
  color:#ffffff !important;

  transition:transform .15s ease, box-shadow .15s ease, opacity .15s ease;
  white-space:nowrap;
}

.mail-btn:hover{
  transform:translateY(-2px);
  box-shadow:0 10px 22px rgba(0,0,0,.18);
  opacity:.95;
}

/* Bouton principal */
.mail-btn.smart{
  background:#111827;
 /* width:100%;*/
  max-width:320px;
  margin:0 auto 12px auto;
}

/* Boutons secondaires */
.mail-buttons{
  display:flex;
 /* flex-wrap:wrap;*/
  gap:10px;
  justify-content:center;
}

.mail-btn.gmail{ background:#ea4335; }
.mail-btn.yahoo{ background:#6001d2; }
.mail-btn.outlook{ background:#0078d4; }

.mail-hint{
  margin-top:12px;
  font-size:13px;
  color:#4b5563;
}

/* ✅ Animation “remonte doucement” */
.animate-up{
  opacity:0;
  transform:translateY(18px);
  animation:cardUp 5s ease-out forwards;
}

@keyframes cardUp{
  to{
    opacity:1;
    transform:translateY(0);
  }
}

@media (max-width:520px){
 /* .mail-btn{ width:100%; }*/
  .mail-confirm-title{ font-size:22px;}
  
  .bx-def-bc-margin {
    margin: 0px 0px 0px 0px;
}
}


</style>

<script>
(function(){
  var emailEl = document.getElementById(\'userEmail\');
  var btn = document.getElementById(\'smartMailLink\');
  if(!emailEl || !btn) return;

  var email = (emailEl.textContent || \'\').toLowerCase();
  var domain = email.split(\'@\')[1] || \'\';

  var url = \'https://mail.google.com\';

  if(domain.includes(\'yahoo\') || domain.includes(\'ymail\')){
    url = \'https://mail.yahoo.com\';
  }else if(
    domain.includes(\'outlook\') ||
    domain.includes(\'hotmail\') ||
    domain.includes(\'live\')
  ){
    url = \'https://outlook.live.com/mail/\';
  }

  btn.href = url;
})();
</script>
