<style>
  /* ===========================
     Jeunesse 243 — Prelaunch Card
     Mobile-first, sans librairie
     =========================== */

  .j243-prelaunch{
  min-height: 100%;
  padding: 18px 12px;

  /* ???? Fond clair premium */
  background:
    radial-gradient(900px 500px at 20% 0%, rgba(13,110,253,.10), transparent 60%),
    radial-gradient(900px 500px at 80% 10%, rgba(0,200,255,.08), transparent 55%),
    #f4f7fb;

  display: flex;
  justify-content: center;
  align-items: flex-start;
}


  .j243-card{
    width: 100%;
    max-width: 680px;
    background: rgba(255,255,255,.96); /* carte lumineuse */
    border-radius: 18px;
    padding: 16px 14px;
    border: 1px solid rgba(255,255,255,.35);

    /* ✅ Ombre portée forte et propre */
    box-shadow:
      0 18px 45px rgba(0,0,0,.55),
      0 2px 0 rgba(255,255,255,.35) inset;

    /* Animation douce d’entrée */
    opacity: 0;
    transform: translateY(10px);
    animation: j243FadeIn 8s ease forwards;
  }

  @keyframes j243FadeIn{
    to{ opacity: 1; transform: translateY(0); }
  }

  .j243-logo{
    display: flex;
    justify-content: center;
    margin-bottom: 10px;
  }

  .j243-logo img{
    height: 44px;
    width: auto;
    display: block;
    filter: drop-shadow(0 6px 14px rgba(0,0,0,.22));
  }

  .j243-title{
    margin: 6px 0 10px 0;
    font-size: 18px;
    line-height: 1.25;
    color: #0b2a57;
    font-weight: 900;
    text-align: center;
  }

