    margin: 0 0 10px 0;
    font-size: 15px;
    line-height: 1.45;
    color: #334155;
  }

  .j243-check{
    color: #16a34a; /* vert */
    font-weight: 900;
    margin-right: 6px;
  }

  .j243-action{
    margin: 12px 0;
    padding: 12px;
    background: linear-gradient(180deg, rgba(13,110,253,.10), rgba(13,110,253,.04));
    border: 1px solid rgba(13,110,253,.22);
    border-radius: 14px;
  }

  .j243-action-label{
    display: flex;
    align-items: center;
    gap: 8px;
    margin-bottom: 6px;
    color: #0b2a57;
    font-size: 14px;
  }

  .j243-dot{
    width: 10px;
    height: 10px;
    border-radius: 999px;
    background: #0d6efd;
    box-shadow: 0 0 0 6px rgba(13,110,253,.16);
    flex: 0 0 auto;
  }

  .j243-list{
    margin: 8px 0 10px 0;
    padding: 0;
    list-style: none;
  }

  .j243-list li{
    display: flex;
    gap: 8px;
    align-items: flex-start;
    margin: 8px 0;
    padding: 10px 10px;
    border-radius: 12px;
    background: #f8fafc;
    border: 1px solid rgba(15,23,42,.08);
    color: #334155;
    font-size: 15px;
    line-height: 1.35;
  }

  .j243-highlight{
    margin-top: 10px;
    padding: 12px;
    border-radius: 14px;
    background: #0b5ed712;
    border: 1px solid rgba(11,94,215,.22);
    color: #0b2a57;
    font-size: 14px;
    line-height: 1.4;
    font-weight: 700;
  }

  .j243-launch{
    margin-top: 14px;
    padding: 12px;
    border-radius: 14px;
    background: #0b1220;
    color: #e5e7eb;
    box-shadow: 0 14px 30px rgba(0,0,0,.35);
  }

  .j243-launch-badge{
    display: inline-block;
    font-size: 12.5px;
    font-weight: 800;
    padding: 6px 10px;
    border-radius: 999px;
    background: rgba(13,110,253,.22);
    border: 1px solid rgba(13,110,253,.35);
    margin-bottom: 8px;
  }

  .j243-launch-date{
    font-size: 14px;
    line-height: 1.4;
    color: #f1f5f9;
  }

  /* Ajustements tablette/desktop */
  @media (min-width: 768px){
    .j243-card{
      padding: 20px 22px;
    }
    .j243-title{
      font-size: 20px;
    }
    .j243-text, .j243-list li, .j243-highlight, .j243-launch-date{
      font-size: 14.5px;
    }
    .j243-logo img{
      height: 52px;
    }
  }
</style>
