<div class="cv-card">
  

  <div class="cv-card__content">
    <span  style="font-size: 22px; font-weight: 900;  text-shadow: #CCC 0 2px 2px;">Compléter mon CV numérique</span>

    <p class="cv-card__desc">
      <i class="fa-solid fa-sliders"></i> Ce CV numérique vous permet de postuler aux offres d’emploi et aux formations.
    </p>

    <p class="cv-card__hint">
      <i class="fa-solid fa-camera"></i>
     Ajoutez une photo professionnelle pour renforcer votre profil et augmenter votre visibilité auprès des recruteurs.
    </p>

   
  </div>
</div>

<style>
  :root{
    --cv-bg:#ffffff;
    --cv-border:#e5e7eb;
    --cv-text:#111827;
    --cv-muted:#6b7280;
    --cv-primary:#0b5ed7;
    --cv-primary-2:#0a58ca;
  }

  .cv-card{
    display:flex;
    gap:14px;
    align-items:flex-start;
    padding:16px;
    border:1px solid var(--cv-border);
    background:var(--cv-bg);
    border-radius:16px;
    box-shadow:0 10px 28px rgba(0,0,0,.08);
    transition:transform .18s ease, box-shadow .18s ease, border-color .18s ease;
    max-width:680px;
  }

  .cv-card:hover{
    transform:translateY(-2px);
    box-shadow:0 14px 34px rgba(0,0,0,.12);
    border-color:rgba(11,94,215,.35);
  }

  .cv-card__icon{
    width:44px;
    height:44px;
    border-radius:12px;
    display:flex;
    align-items:center;
    justify-content:center;
    background:rgba(11,94,215,.10);
    color:var(--cv-primary);
    flex:0 0 auto;
  }

  .cv-card__icon i{
    font-size:18px;
  }

  .cv-card__content{
    min-width:0;
    flex:1 1 auto;
  }

  .cv-card__title{
    margin:0 0 6px 0;
    font-size:16px;
    font-weight:900;
    color:var(--cv-text);
    line-height:1.2;
  }

  .cv-card__desc{
    margin:0 0 10px 0;
    font-size:13.5px;
    color:var(--cv-muted);
    line-height:1.35;
  }

  .cv-card__hint{
    margin:0 0 12px 0;
    font-size:13.5px;
    color:var(--cv-muted);
    line-height:1.35;
    display:flex;
    align-items:flex-start;
    gap:8px;
  }

  .cv-card__hint i{
    margin-top:1px;
    color:var(--cv-primary);
    flex:0 0 auto;
  }

  .cv-card__btn{
    display:inline-flex;
    align-items:center;
    gap:10px;
    padding:10px 14px;
    border-radius:12px;
    background:var(--cv-primary);
    color:#fff;
    text-decoration:none;
    font-weight:800;
    font-size:13.5px;
    line-height:1;
    box-shadow:0 10px 22px rgba(11,94,215,.25);
    transition:transform .18s ease, box-shadow .18s ease, background-color .18s ease;
    white-space:nowrap;
  }

  .cv-card__btn:hover{
    background:var(--cv-primary-2);
    transform:translateY(-1px);
    box-shadow:0 14px 28px rgba(11,94,215,.30);
  }

  .cv-card__btn i{
    font-size:14px;
  }

  /* Mobile: compact */
  @media (max-width:520px){
    .cv-card{
      padding:14px;
      gap:12px;
    }
    .cv-card__btn{
      width:100%;
      justify-content:center;
    }
  }
</style>
